1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
15	    const currentGen = [[0, 0], [1, 0], [0, 1]];
16	    const result = nextGeneration(currentGen);
17	    const sorted = (g: number[][]) => [...g].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    expect(sorted(result)).toEqual(sorted([[0, 0], [1, 0], [0, 1], [1, 1]]));
19	  });
20	  it("should keep a live cell alive when it has exactly 2 live neighbors (survival)", () => {
21	    const currentGen = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(currentGen);
23	    expect(result).toContainEqual([0, 1]);
24	  });
25	  it("should keep a live cell alive when it has exactly 3 live neighbors (survival)", () => {
26	    const currentGen = [[0, 0], [1, 0], [2, 0], [1, 1]];
27	    const result = nextGeneration(currentGen);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it.todo("should kill a live cell when it has 4 or more live neighbors (overpopulation)");
31	  it.todo("should keep a block pattern stable across generations (still life)");
32	  it.todo("should oscillate a blinker pattern to its alternate form");
33	});
34

1	export function nextGeneration(grid: number[][]): number[][] {
2	  if (grid.length === 0) return [];
3	
4	  const alive = new Set(grid.map(([x, y]) => `${x},${y}`));
5	
6	  const neighborCounts = new Map<string, number>();
7	
8	  for (const [x, y] of grid) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const key = `${x + dx},${y + dy}`;
13	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
14	      }
15	    }
16	  }
17	
18	  const result: number[][] = [];
19	
20	  for (const [key, count] of neighborCounts) {
21	    const [x, y] = key.split(",").map(Number);
22	    if (count === 3 || (count === 2 && alive.has(key))) {
23	      result.push([x, y]);
24	    }
25	  }
26	
27	  return result;
28	}
29

